#!/usr/bin/env python3
"""
bootstrap_suprabank_refit.py — HG parameter re-calibration + physics modules.

From 1552 SupraBank entries (overall MAE 5.48 -> 1.75, -68%):
  Parameter re-fit (gamma, dehydr, HB, shape, conf)
  Portal cap at 4.1 kJ/mol
  PC-dependent CB dehydration (2x at low filling)
  pH-aware pKa estimation (14 SMARTS, Henderson-Hasselbalch)
  Reduced water penalty for charge-assisted H-bonds
  3D inclusion classifier (axial x radial depth, gates future HEW)
  HEW model code preserved dormant (needs selective activation model)

Deploy: bootstrap_suprabank_ingest.py FIRST, then this bootstrap.
Tests: python -m pytest tests/test_pka_estimator.py tests/test_suprabank_refit.py -v
"""
import base64, os, sys
ROOT = os.path.dirname(os.path.abspath(__file__))
if not os.path.exists(os.path.join(ROOT, "core", "universal_schema.py")):
    ROOT = os.path.dirname(ROOT)
    if not os.path.exists(os.path.join(ROOT, "core", "universal_schema.py")):
        print("ERROR: Run from MABE repo root"); sys.exit(1)
FILES = {}
FILES["hg_scorer.py"] = ""
FILES["knowledge/hg_hbond.py"] = ""
FILES["knowledge/hg_conf_shape.py"] = ""
FILES["core/unified_scorer_v2.py"] = ""
FILES["core/pka_estimator.py"] = ""
FILES["core/inclusion_classifier.py"] = ""
FILES["tests/test_suprabank_refit.py"] = ""
FILES["tests/test_pka_estimator.py"] = ""
FILES["data/suprabank_scoring_pka.json"] = ""
FILES["data/suprabank_new_params.json"] = ""

n = 0
for rel_path, b64 in FILES.items():
    full = os.path.join(ROOT, rel_path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "w", encoding="utf-8") as f:
        f.write(base64.b64decode(b64).decode("utf-8"))
    n += 1; print(f"  written: {rel_path}")

print(f"\nBootstrap complete: {n} files written.")